from elasticsearch import Elasticsearch
import logging

es = Elasticsearch([{'host': 'localhost', 'port': 9200}])
index_name = "centralized_logs"
doc_type = "_doc"

# Index a document
def index_document(doc_id, doc):
    es.indices.create(index=index_name)
    es.index(index=index_name, doc_type=doc_type, id=doc_id, body=doc)

# Aggregate logs for a specific log level
def aggregate_logs(log_level):
    query = {
        "query": {
            "bool": {
                "must": [
                    {"match": {"level": log_level}}
                ]
            }
        },
        "aggs": {
            "by_time": {
                "date_histogram": {
                    "field": "timestamp",
                    "interval": "1h"
                }
            }
        }
    }
    result = es.search(index=index_name, body=query)
    return result["aggregations"]["by_time"]["buckets"]

# Full-text search
def search_documents(query):
    query = {
        "query": {
            "multi_match": {
                "query": query,
                "fields": ["message^2", "tags"]
            }
        }
    }
    result = es.search(index=index_name, body=query)
    return result["hits"]["hits"]

# Logging example with logging module
import time
logging.basicConfig(format='%(asctime)s [%(levelname) 8s] %(message)s', level=logging.INFO)
logger = logging.getLogger(__name__)

def log_event(message, tags={}, log_level="info"):
    doc = {
        "timestamp": int(time.time()),
        "level": log_level,
        "message": message,
        "tags": tags
    }
    index_document("doc_{}".format(len(es.search(index=index_name))), doc)
    logger.log(log_level, message)